# ======================================================
#  EMBEDDED LOGO  (512x512 PNG, base64)
# ======================================================
_LOGO_B64 = """"""



def get_logo_pixmap(size=48):
    try:
        data = _b64.b64decode(_LOGO_B64)
        pix = QPixmap()
        pix.loadFromData(data)  # auto-detects JPEG/PNG
        if size:
            pix = pix.scaled(size, size,
                Qt.AspectRatioMode.KeepAspectRatio,
                Qt.TransformationMode.SmoothTransformation)
        return pix
    except:
        return QPixmap()

def get_logo_icon():
    return QIcon(get_logo_pixmap(256))


