def is_admin():
    try:
        return ctypes.windll.shell32.IsUserAnAdmin()
    except:
        return False

def relaunch_as_admin():
    ctypes.windll.shell32.ShellExecuteW(
        None, "runas", sys.executable, " ".join(sys.argv), None, 1
    )
    sys.exit(0)


# ══════════════════════════════════════════════════════════
#  SILENT SUBPROCESS  —  THE POPUP FIX
#  Every subprocess call uses:
#   1. creationflags=CREATE_NO_WINDOW (0x08000000)
#   2. startupinfo with SW_HIDE
#  This eliminates ALL CMD/PowerShell popups at the OS level.
# ══════════════════════════════════════════════════════════
_NO_WINDOW = 0x08000000

def _si():
    """STARTUPINFO that hides the child process window."""
    si = subprocess.STARTUPINFO()
    si.dwFlags |= subprocess.STARTF_USESHOWWINDOW
    si.wShowWindow = subprocess.SW_HIDE
    return si

def run(cmd, timeout=30):
    try:
        subprocess.run(cmd, shell=True, capture_output=True, timeout=timeout,
                       creationflags=_NO_WINDOW, startupinfo=_si())
        return True
    except:
        return False

def run_ps(script, timeout=60):
    try:
        subprocess.run(
            ["powershell", "-NoProfile", "-NonInteractive",
             "-WindowStyle", "Hidden", "-Command", script],
            capture_output=True, timeout=timeout,
            creationflags=_NO_WINDOW, startupinfo=_si()
        )
        return True
    except:
        return False

def run_get(cmd, timeout=10):
    try:
        r = subprocess.run(cmd, shell=True, capture_output=True, text=True,
                           timeout=timeout, creationflags=_NO_WINDOW, startupinfo=_si())
        return r.stdout.strip()
    except:
        return ""

def _ps_get(expr, timeout=10):
    try:
        r = subprocess.run(
            ["powershell", "-NoProfile", "-NonInteractive",
             "-WindowStyle", "Hidden", "-Command", expr],
            capture_output=True, text=True, timeout=timeout,
            creationflags=_NO_WINDOW, startupinfo=_si()
        )
        lines = [l.strip() for l in r.stdout.splitlines() if l.strip()]
        return lines[-1] if lines else ""
    except:
        return ""


# ══════════════════════════════════════════════════════════
#  REGISTRY HELPERS
# ══════════════════════════════════════════════════════════
def rset(path, name, value, vtype=winreg.REG_DWORD, hive=winreg.HKEY_LOCAL_MACHINE):
    try:
        k = winreg.CreateKeyEx(hive, path, 0, winreg.KEY_SET_VALUE)
        winreg.SetValueEx(k, name, 0, vtype, value)
        winreg.CloseKey(k)
        return True
    except:
        return False

def rdel(path, name, hive=winreg.HKEY_LOCAL_MACHINE):
    try:
        k = winreg.OpenKey(hive, path, 0, winreg.KEY_SET_VALUE)
        winreg.DeleteValue(k, name)
        winreg.CloseKey(k)
        return True
    except:
        return False

def rget(path, name, hive=winreg.HKEY_LOCAL_MACHINE):
    try:
        k = winreg.OpenKey(hive, path, 0, winreg.KEY_READ)
        v, _ = winreg.QueryValueEx(k, name)
        winreg.CloseKey(k)
        return v
    except:
        return None

def svc(name, mode):
    run(f'sc config "{name}" start= {mode}')
    if mode == "disabled":
        run(f'sc stop "{name}"')

def has_nvidia():
    return "nvidia" in run_get("wmic path win32_VideoController get Name").lower()

def is_laptop():
    out = run_get("wmic SystemEnclosure get ChassisTypes")
    laptop_types = {'8','9','10','11','12','14','18','21','30','31','32'}
    return bool(set(re.findall(r'\d+', out)) & laptop_types)


# ══════════════════════════════════════════════════════════
#  PC SPECS  (all subprocess calls hidden)
# ══════════════════════════════════════════════════════════
def get_pc_specs():
    specs = {}
    try:
        cpu = rget(r"HARDWARE\DESCRIPTION\System\CentralProcessor\0",
                   "ProcessorNameString")
        specs["cpu"] = cpu.strip() if cpu else _ps_get(
            "(Get-WmiObject Win32_Processor | Select-Object -First 1).Name")
    except:
        specs["cpu"] = "Unknown"
    try:
        out = _ps_get(
            "(Get-WmiObject Win32_VideoController | Where-Object "
            "{$_.Name -notmatch 'Microsoft'} | Select-Object -ExpandProperty Name) -join ' / '")
        specs["gpu"] = out or "Unknown"
    except:
        specs["gpu"] = "Unknown"
    try:
        raw = _ps_get("(Get-WmiObject Win32_ComputerSystem).TotalPhysicalMemory")
        specs["ram"] = f"{round(int(raw)/1073741824)} GB" if raw.isdigit() else "Unknown"
    except:
        specs["ram"] = "Unknown"
    try:
        specs["os"] = _ps_get("(Get-WmiObject Win32_OperatingSystem).Caption").strip()
    except:
        specs["os"] = platform.version()
    try:
        specs["build"] = _ps_get("(Get-WmiObject Win32_OperatingSystem).BuildNumber").strip()
    except:
        specs["build"] = "Unknown"
    try:
        raw = _ps_get(
            "(Get-WmiObject Win32_DiskDrive | Sort-Object Size -Descending"
            " | Select-Object -First 1).Size")
        specs["disk"] = f"{round(int(raw)/1e9)} GB SSD/HDD" if raw.isdigit() else "Unknown"
    except:
        specs["disk"] = "Unknown"
    specs["arch"]  = platform.machine()
    specs["host"]  = socket.gethostname()
    specs["admin"] = "Yes" if is_admin() else "No"
    specs["form"]  = "Laptop" if is_laptop() else "Desktop"
    try:
        nv = _ps_get(
            "(Get-WmiObject Win32_VideoController | Where-Object "
            "{$_.Name -match 'NVIDIA'} | Select-Object -First 1).Name")
        specs["nvidia"] = nv or "Not detected"
    except:
        specs["nvidia"] = "Not detected"
    try:
        cores   = _ps_get("(Get-WmiObject Win32_Processor | Select-Object -First 1).NumberOfCores")
        threads = _ps_get("(Get-WmiObject Win32_Processor | Select-Object -First 1).NumberOfLogicalProcessors")
        if cores and threads:
            specs["cores"] = f"{cores} Cores / {threads} Threads"
    except:
        pass
    try:
        spd = _ps_get("(Get-WmiObject Win32_PhysicalMemory | Select-Object -First 1).Speed")
        if spd:
            specs["ram_speed"] = f"{spd} MT/s"
    except:
        pass
    try:
        model = _ps_get(
            "(Get-WmiObject Win32_DiskDrive | Sort-Object Size -Descending"
            " | Select-Object -First 1).Model")
        if model:
            specs["disk_model"] = model
    except:
        pass
    return specs


