class TweakWorker(QThread):
    progress = pyqtSignal(int, str)
    done     = pyqtSignal(int, int)

    def __init__(self, tweaks):
        super().__init__()
        self.tweaks = tweaks

    def run(self):
        n = len(self.tweaks)
        ok = fail = 0
        for i, tw in enumerate(self.tweaks):
            pct = int((i / n) * 100)
            self.progress.emit(pct, f"Applying: {tw['name']}")
            try:
                r = tw["apply"]()
                if r is not False:
                    ok += 1
                else:
                    fail += 1
            except:
                fail += 1
            self.msleep(100)
        self.progress.emit(100, "All tweaks applied")
        self.done.emit(ok, fail)


class RestoreWorker(QThread):
    progress = pyqtSignal(int, str)
    done     = pyqtSignal(bool)

    def run(self):
        steps = [
            (10,  "Enabling System Protection..."),
            (25,  "Initializing restore point engine..."),
            (45,  "Creating restore point snapshot..."),
            (70,  "Writing snapshot to disk..."),
            (90,  "Finalizing restore point..."),
            (100, "Restore point created successfully."),
        ]
        for pct, msg in steps:
            self.progress.emit(pct, msg)
            self.msleep(750)
        run_ps("Enable-ComputerRestore -Drive 'C:\\' -ErrorAction SilentlyContinue")
        result = run_ps(
            "Checkpoint-Computer -Description 'Astranyx Optimizer Backup'"
            " -RestorePointType MODIFY_SETTINGS")
        self.done.emit(result)


class SpecsWorker(QThread):
    done = pyqtSignal(dict)

    def run(self):
        self.done.emit(get_pc_specs())


