class ToggleSwitch(QWidget):
    """60fps animated toggle with cubic easing and gradient track."""
    toggled = pyqtSignal(bool)

    def __init__(self, parent=None):
        super().__init__(parent)
        self._checked = False
        self._pos = 0.0          # 0.0=off  1.0=on
        self.setFixedSize(46, 24)
        self.setCursor(QCursor(Qt.CursorShape.PointingHandCursor))
        self._t = QTimer(self)
        self._t.timeout.connect(self._anim)
        self._t.setInterval(16)  # 60fps

    def isChecked(self): return self._checked

    def setChecked(self, v):
        self._checked = v
        self._pos = 1.0 if v else 0.0
        self.update()

    def _anim(self):
        tgt = 1.0 if self._checked else 0.0
        d = tgt - self._pos
        if abs(d) < 0.04:
            self._pos = tgt
            self._t.stop()
        else:
            self._pos += d * 0.22   # cubic-ish ease
        self.update()

    def mousePressEvent(self, e):
        if e.button() == Qt.MouseButton.LeftButton:
            self._checked = not self._checked
            self._t.start()
            self.toggled.emit(self._checked)

    def paintEvent(self, e):
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)
        w, h = self.width(), self.height()
        r = h / 2
        t = self._pos

        # Blend track color: off (#282845) → on (#5e3fd4 → #7c5cfc)
        or_, og, ob = 0x28, 0x28, 0x45
        nr,  ng, nb = 0x5e, 0x3f, 0xd4
        cr = int(or_ + (nr - or_) * t)
        cg = int(og  + (ng - og)  * t)
        cb = int(ob  + (nb - ob)  * t)

        g = QLinearGradient(0, 0, w, 0)
        g.setColorAt(0, QColor(cr, cg, cb))
        g.setColorAt(1, QColor(
            min(255, int(cr + 30 * t)),
            min(255, int(cg + 20 * t)),
            min(255, int(cb + 40 * t))
        ))
        p.setPen(Qt.PenStyle.NoPen)
        p.setBrush(QBrush(g))
        p.drawRoundedRect(0, 0, w, h, r, r)

        # Knob
        pad = 3
        kd  = h - pad * 2
        kx  = pad + t * (w - h)
        kc  = QColor("#ffffff") if t > 0.5 else QColor(T.TEXT3)
        p.setBrush(QBrush(kc))
        if t > 0.25:
            p.setPen(QPen(QColor(124, 92, 252, int(90 * t)), 1.2))
        else:
            p.setPen(Qt.PenStyle.NoPen)
        p.drawEllipse(int(kx), pad, kd, kd)
        p.end()


class RiskBadge(QLabel):
    _MAP = {
        "safe":    ("#0b2e1c", "#3de098", "SAFE"),
        "caution": ("#2a1d06", "#f5c842", "CAUTION"),
        "risk":    ("#2a0d10", "#f07070", "RISK"),
    }

    def __init__(self, risk, parent=None):
        super().__init__(parent)
        bg, fg, label = self._MAP.get(risk, self._MAP["safe"])
        self.setText(label)
        self.setStyleSheet(f"""
            QLabel {{
                background: {bg}; color: {fg};
                border: 1px solid {fg}38;
                border-radius: 5px; padding: 2px 8px;
                font-size: 8.5px; font-weight: 700; letter-spacing: 1.2px;
            }}
        """)


class TweakCard(QFrame):
    """Glass-morphism tweak card with smooth violet hover glow."""
    _SS_NORMAL = """
        QFrame#tc {
            background: rgba(255,255,255,0.026);
            border: 1px solid rgba(255,255,255,0.062);
            border-radius: 14px;
        }
    """
    _SS_HOVER = """
        QFrame#tc {
            background: rgba(124,92,252,0.072);
            border: 1px solid rgba(124,92,252,0.20);
            border-radius: 14px;
        }
    """

    def __init__(self, tweak, parent=None):
        super().__init__(parent)
        self.tweak = tweak
        self.setObjectName("tc")
        self.setFixedHeight(118)
        self.setMouseTracking(True)
        self.setStyleSheet(self._SS_NORMAL)
        self._build()

    def _build(self):
        ly = QVBoxLayout(self)
        ly.setContentsMargins(18, 14, 16, 13)
        ly.setSpacing(5)

        top = QHBoxLayout()
        top.setSpacing(10)
        name = QLabel(self.tweak["name"])
        name.setStyleSheet(
            f"font-size: 12.5px; font-weight: 600; color: {T.TEXT};"
            " background: transparent; border: none; letter-spacing: -0.1px;"
        )
        top.addWidget(name, 1)
        top.addWidget(RiskBadge(self.tweak.get("risk", "safe")))
        ly.addLayout(top)

        desc = QLabel(self.tweak["desc"])
        desc.setWordWrap(True)
        desc.setStyleSheet(
            f"font-size: 10.5px; color: {T.TEXT2}; line-height: 1.4;"
            " background: transparent; border: none;"
        )
        ly.addWidget(desc, 1)

        bot = QHBoxLayout()
        bot.setContentsMargins(0, 2, 0, 0)
        bot.addStretch()
        self.toggle = ToggleSwitch()
        self.toggle.toggled.connect(self._bubble_counter)
        bot.addWidget(self.toggle)
        ly.addLayout(bot)

    def _bubble_counter(self, _):
        p = self.parent()
        while p:
            if hasattr(p, '_update_counter'):
                p._update_counter()
                return
            p = p.parent() if hasattr(p, 'parent') else None

    def is_on(self): return self.toggle.isChecked()

    def enterEvent(self, e): self.setStyleSheet(self._SS_HOVER)
    def leaveEvent(self, e): self.setStyleSheet(self._SS_NORMAL)


