class NavItem(QWidget):
    """Sidebar nav item with gradient accent bar and smooth hover."""
    clicked = pyqtSignal(int)

    def __init__(self, idx, label, parent=None):
        super().__init__(parent)
        self.idx = idx
        self._active = False
        self.setFixedHeight(38)
        self.setCursor(QCursor(Qt.CursorShape.PointingHandCursor))
        ly = QHBoxLayout(self)
        ly.setContentsMargins(0, 0, 12, 0)
        ly.setSpacing(0)
        self._bar = QFrame()
        self._bar.setFixedWidth(3)
        self._bar.setFixedHeight(20)
        ly.addWidget(self._bar)
        ly.addSpacing(15)
        self._label = QLabel(label)
        ly.addWidget(self._label, 1)
        self._update()

    def setActive(self, a):
        self._active = a
        self._update()

    def _update(self):
        if self._active:
            self._bar.setStyleSheet(
                f"background: qlineargradient(x1:0,y1:0,x2:0,y2:1,"
                f"stop:0 {T.ACC}, stop:1 {T.PINK}); border-radius: 1.5px;"
            )
            self._label.setStyleSheet(
                f"font-size: 12.5px; font-weight: 650; color: {T.TEXT}; letter-spacing: 0.1px;"
            )
            self.setStyleSheet(
                f"background: qlineargradient(x1:0,y1:0,x2:1,y2:0,"
                f"stop:0 rgba(124,92,252,0.13), stop:1 rgba(124,92,252,0.0));"
            )
        else:
            self._bar.setStyleSheet("background: transparent; border-radius: 1.5px;")
            self._label.setStyleSheet(
                f"font-size: 12px; font-weight: 400; color: {T.TEXT_DIM};"
            )
            self.setStyleSheet("background: transparent;")

    def enterEvent(self, e):
        if not self._active:
            self._label.setStyleSheet(f"font-size: 12px; font-weight: 400; color: {T.TEXT2};")
            self.setStyleSheet("background: rgba(255,255,255,0.025);")

    def leaveEvent(self, e):
        if not self._active:
            self._update()

    def mousePressEvent(self, e):
        if e.button() == Qt.MouseButton.LeftButton:
            self.clicked.emit(self.idx)


