def scroll_wrap(widget):
    sa = QScrollArea()
    sa.setWidget(widget)
    sa.setWidgetResizable(True)
    sa.setFrameShape(QFrame.Shape.NoFrame)
    sa.setStyleSheet("background: transparent;")
    sa.setHorizontalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAlwaysOff)
    return sa


def make_section_grid(tweaks_list):
    w = QWidget()
    w.setStyleSheet("background: transparent;")
    from PyQt6.QtWidgets import QGridLayout
    g = QGridLayout(w)
    g.setContentsMargins(0, 0, 0, 8)
    g.setSpacing(10)
    cards = []
    for i, tw in enumerate(tweaks_list):
        c = TweakCard(tw)
        g.addWidget(c, i // 2, i % 2)
        cards.append(c)
    return w, cards


def build_multi_section_page(sections):
    page = QWidget()
    page.setStyleSheet("background: transparent;")
    outer = QVBoxLayout(page)
    outer.setContentsMargins(32, 10, 32, 24)
    outer.setSpacing(0)
    all_cards = []
    for sec_title, tweaks_list in sections:
        if sec_title:
            outer.addWidget(SectionHeader(sec_title))
        gw, cards = make_section_grid(tweaks_list)
        outer.addWidget(gw)
        all_cards.extend(cards)
    outer.addStretch()
    return page, all_cards


def build_tabbed_page(tabs_data):
    page = QWidget()
    page.setStyleSheet("background: transparent;")
    ml = QVBoxLayout(page)
    ml.setContentsMargins(0, 0, 0, 0)
    ml.setSpacing(0)

    tab_bar = QWidget()
    tab_bar.setFixedHeight(46)
    tab_bar.setStyleSheet(
        "background: rgba(11,11,22,0.96);"
        "border-bottom: 1px solid rgba(255,255,255,0.055);"
    )
    tbl = QHBoxLayout(tab_bar)
    tbl.setContentsMargins(28, 0, 28, 0)
    tbl.setSpacing(2)

    stack = QStackedWidget()
    stack.setStyleSheet("background: transparent;")
    tab_btns = []
    all_cards = {}

    for i, (label, sections) in enumerate(tabs_data):
        btn = QPushButton(label)
        btn.setFixedHeight(38)
        btn.setCheckable(True)
        btn.setCursor(QCursor(Qt.CursorShape.PointingHandCursor))
        tab_btns.append(btn)

        inner = QWidget()
        inner.setStyleSheet("background: transparent;")
        il = QVBoxLayout(inner)
        il.setContentsMargins(32, 10, 32, 24)
        il.setSpacing(0)
        cards = []
        for sec_title, tweaks_list in sections:
            if sec_title:
                il.addWidget(SectionHeader(sec_title))
            gw, c = make_section_grid(tweaks_list)
            il.addWidget(gw)
            cards.extend(c)
        il.addStretch()
        stack.addWidget(scroll_wrap(inner))
        all_cards[label] = cards

    def activate_tab(idx):
        stack.setCurrentIndex(idx)
        for j, b in enumerate(tab_btns):
            if j == idx:
                b.setStyleSheet(f"""
                    QPushButton {{
                        background: transparent; color: {T.ACC3}; border: none;
                        border-bottom: 2px solid {T.ACC}; font-size: 12px;
                        font-weight: 700; padding: 0 16px; border-radius: 0;
                    }}
                """)
            else:
                b.setStyleSheet(f"""
                    QPushButton {{
                        background: transparent; color: {T.TEXT_DIM}; border: none;
                        border-bottom: 2px solid transparent; font-size: 12px;
                        font-weight: 500; padding: 0 16px; border-radius: 0;
                    }}
                    QPushButton:hover {{ color: {T.TEXT2}; }}
                """)

    for i, btn in enumerate(tab_btns):
        btn.clicked.connect(lambda _, ii=i: activate_tab(ii))
        tbl.addWidget(btn)
    tbl.addStretch()
    activate_tab(0)

    ml.addWidget(tab_bar)
    ml.addWidget(stack)
    page._all_cards = all_cards
    return page, all_cards




# ══════════════════════════════════════════════════════════
#  DASHBOARD PAGE  v3.0
# ══════════════════════════════════════════════════════════
def build_dashboard(main_window):
    page = QWidget()
    page.setStyleSheet("background: transparent;")
    outer = QScrollArea()
    outer.setWidgetResizable(True)
    outer.setFrameShape(QFrame.Shape.NoFrame)
    outer.setStyleSheet("background: transparent;")
    outer.setHorizontalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAlwaysOff)

    content = QWidget()
    content.setStyleSheet("background: transparent;")
    ly = QVBoxLayout(content)
    ly.setContentsMargins(32, 26, 32, 32)
    ly.setSpacing(20)

    # Hero row
    hero = QHBoxLayout()
    hero.setSpacing(18)
    dash_logo = QLabel()
    dash_logo.setFixedSize(68, 68)
    dash_logo.setAlignment(Qt.AlignmentFlag.AlignCenter)
    try:
        dash_logo.setPixmap(get_logo_pixmap(68))
    except Exception:
        dash_logo.setText("A")
        dash_logo.setStyleSheet(f"font-size: 36px; font-weight: 900; color: {T.ACC3};")
    hero.addWidget(dash_logo)

    tl = QVBoxLayout()
    tl.setSpacing(4)
    tl.setAlignment(Qt.AlignmentFlag.AlignVCenter)
    t1 = QLabel("Astranyx Optimizer")
    t1.setStyleSheet(
        f"font-size: 26px; font-weight: 800; color: {T.TEXT}; letter-spacing: -0.5px;"
    )
    t2 = QLabel("Advanced Windows Performance & Privacy Suite  ·  v3.0")
    t2.setStyleSheet(f"font-size: 11.5px; color: {T.TEXT2};")
    tl.addWidget(t1)
    tl.addWidget(t2)
    hero.addLayout(tl)
    hero.addStretch()

    ok = is_admin()
    admin_badge = QLabel("  ADMINISTRATOR  " if ok else "  NOT ADMIN  ")
    admin_badge.setStyleSheet(f"""
        background: {'rgba(74,222,128,0.12)' if ok else T.RISK_BG};
        color: {T.GREEN if ok else T.RED};
        border: 1px solid {'rgba(74,222,128,0.35)' if ok else 'rgba(240,113,113,0.3)'};
        border-radius: 7px; font-size: 10px; font-weight: 700;
        padding: 6px 12px; letter-spacing: 0.8px;
    """)
    hero.addWidget(admin_badge)
    ly.addLayout(hero)

    # Stat cards
    ALL = _tweaks()
    total = sum(len(v) for v in ALL.values())
    stats = [
        ("Total Tweaks",  str(total),                         T.ACC),
        ("Categories",    str(len(ALL)),                      T.TEAL),
        ("Quick Fixes",   str(len(ALL.get("quick", []))),     T.GOLD),
        ("Free to Use",   "100%",                             T.GREEN),
    ]
    stat_row = QHBoxLayout()
    stat_row.setSpacing(12)
    for lbl, val, col in stats:
        f = QFrame()
        f.setStyleSheet("""
            QFrame { background: rgba(255,255,255,0.027); border: 1px solid rgba(255,255,255,0.07); border-radius: 14px; }
            QFrame QLabel { background: transparent; border: none; }
        """)
        fl = QVBoxLayout(f)
        fl.setContentsMargins(18, 14, 18, 14)
        fl.setSpacing(3)
        vl = QLabel(val)
        vl.setStyleSheet(f"font-size: 22px; font-weight: 800; color: {col}; letter-spacing: -0.5px;")
        ll = QLabel(lbl)
        ll.setStyleSheet(f"font-size: 9px; font-weight: 600; color: {T.TEXT3}; letter-spacing: 0.5px;")
        fl.addWidget(vl)
        fl.addWidget(ll)
        stat_row.addWidget(f)
    ly.addLayout(stat_row)

    # PC Specs card
    specs_card = QFrame()
    specs_card.setObjectName("sc")
    specs_card.setStyleSheet("""
        QFrame#sc { background: rgba(255,255,255,0.027); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; }
        QFrame#sc QLabel { background: transparent; border: none; }
    """)
    specs_ly = QVBoxLayout(specs_card)
    specs_ly.setContentsMargins(22, 18, 22, 18)
    specs_ly.setSpacing(12)

    sh_row = QHBoxLayout()
    sh_lbl = QLabel("System Specifications")
    sh_lbl.setStyleSheet(f"font-size: 11px; font-weight: 700; color: {T.TEXT2}; letter-spacing: 0.3px;")
    sh_row.addWidget(sh_lbl)
    sh_row.addStretch()
    page._refresh_btn = ActionButton("Refresh", "secondary")
    page._refresh_btn.setFixedWidth(90)
    page._refresh_btn.setFixedHeight(30)
    sh_row.addWidget(page._refresh_btn)
    specs_ly.addLayout(sh_row)

    from PyQt6.QtWidgets import QGridLayout
    page._specs_grid = QGridLayout()
    page._specs_grid.setSpacing(8)
    page._specs_grid.setColumnStretch(0, 1)
    page._specs_grid.setColumnStretch(1, 1)
    specs_ly.addLayout(page._specs_grid)

    page._loading_lbl = QLabel("Loading system information...")
    page._loading_lbl.setStyleSheet(f"font-size: 11px; color: {T.TEXT2};")
    specs_ly.addWidget(page._loading_lbl)
    ly.addWidget(specs_card)

    def populate_specs(specs):
        page._loading_lbl.hide()
        while page._specs_grid.count():
            item = page._specs_grid.takeAt(0)
            if item.widget():
                item.widget().deleteLater()
        fields = [
            ("Processor",        specs.get("cpu", "—")),
            ("Graphics Card",    specs.get("gpu", "—")),
            ("RAM",              specs.get("ram", "—") + (
                "  ·  " + specs["ram_speed"] if "ram_speed" in specs else "")),
            ("CPU Cores",        specs.get("cores", "—")),
            ("Operating System", specs.get("os", "—")),
            ("Windows Build",    specs.get("build", "—")),
            ("Architecture",     specs.get("arch", "—")),
            ("Storage",          (specs.get("disk_model","") + "  " + specs.get("disk","")).strip() or "—"),
            ("Hostname",         specs.get("host", "—")),
            ("Form Factor",      specs.get("form", "—")),
            ("NVIDIA GPU",       specs.get("nvidia", "—")),
            ("Administrator",    specs.get("admin", "—")),
        ]
        for i, (k, v) in enumerate(fields):
            row, col = divmod(i, 2)
            cell = QFrame()
            cell.setObjectName("speccell")
            cell.setStyleSheet("""
                QFrame#speccell { background: rgba(255,255,255,0.03); border-radius: 10px; border: 1px solid rgba(255,255,255,0.062); }
                QFrame#speccell QLabel { background: transparent; border: none; }
            """)
            cl = QVBoxLayout(cell)
            cl.setContentsMargins(14, 11, 14, 11)
            cl.setSpacing(3)
            kl = QLabel(k.upper())
            kl.setStyleSheet(f"font-size: 8.5px; font-weight: 700; color: {T.TEXT3}; letter-spacing: 0.8px;")
            dv = str(v)
            vl = QLabel(dv[:70] if len(dv) > 70 else dv)
            vl.setWordWrap(True)
            vl.setStyleSheet(f"font-size: 13px; font-weight: 500; color: {T.TEXT};")
            cl.addWidget(kl)
            cl.addWidget(vl)
            page._specs_grid.addWidget(cell, row, col)

    def load_specs():
        page._loading_lbl.show()
        w = SpecsWorker()
        w.done.connect(populate_specs)
        page._specs_worker = w
        w.start()

    page._refresh_btn.clicked.connect(load_specs)
    QTimer.singleShot(350, load_specs)   # deferred start — zero startup blocking

    # Restore Point card
    rp_card = QFrame()
    rp_card.setObjectName("rp")
    rp_card.setStyleSheet("""
        QFrame#rp { background: rgba(255,255,255,0.027); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; }
        QFrame#rp QLabel { background: transparent; border: none; }
    """)
    rp_ly = QVBoxLayout(rp_card)
    rp_ly.setContentsMargins(22, 18, 22, 18)
    rp_ly.setSpacing(10)

    rp_top = QHBoxLayout()
    rp_title = QLabel("System Restore Point")
    rp_title.setStyleSheet(f"font-size: 11px; font-weight: 700; color: {T.TEXT2}; letter-spacing: 0.3px;")
    rp_desc = QLabel(
        "Recommended before applying tweaks. Creates a Windows snapshot "
        "to roll back if something goes wrong."
    )
    rp_desc.setStyleSheet(f"font-size: 11px; color: {T.TEXT2};")
    page._rp_btn = ActionButton("Create Restore Point", "secondary")
    page._rp_btn.setFixedWidth(188)
    rp_top.addWidget(rp_title)
    rp_top.addStretch()
    rp_top.addWidget(page._rp_btn)
    rp_ly.addLayout(rp_top)
    rp_ly.addWidget(rp_desc)

    page._rp_bar = QProgressBar()
    page._rp_bar.setFixedHeight(6)
    page._rp_bar.setTextVisible(False)
    page._rp_bar.setVisible(False)
    page._rp_bar.setStyleSheet(f"""
        QProgressBar {{ background: {T.BORDER}; border-radius: 3px; border: none; }}
        QProgressBar::chunk {{
            background: qlineargradient(x1:0,y1:0,x2:1,y2:0,
                stop:0 {T.TEAL}, stop:1 {T.ACC}); border-radius: 3px;
        }}
    """)
    rp_ly.addWidget(page._rp_bar)

    page._rp_status = QLabel("")
    page._rp_status.setStyleSheet(f"font-size: 10.5px; color: {T.TEAL};")
    page._rp_status.setVisible(False)
    rp_ly.addWidget(page._rp_status)

    def rp_progress(pct, msg):
        page._rp_bar.setValue(pct)
        page._rp_status.setText(msg)

    def rp_done(ok):
        page._rp_btn.setEnabled(True)
        page._rp_status.setText(
            "Restore point created successfully." if ok
            else "Done (verify in System Restore)."
        )
        QTimer.singleShot(6000, lambda: (
            page._rp_bar.setVisible(False), page._rp_status.setVisible(False)
        ))

    def create_rp():
        page._rp_btn.setEnabled(False)
        page._rp_bar.setValue(0)
        page._rp_bar.setVisible(True)
        page._rp_status.setText("Starting...")
        page._rp_status.setVisible(True)
        worker = RestoreWorker()
        page._rp_worker = worker
        worker.progress.connect(rp_progress)
        worker.done.connect(rp_done)
        worker.start()

    page._rp_btn.clicked.connect(create_rp)
    ly.addWidget(rp_card)

    # How-to card
    how = QFrame()
    how.setStyleSheet(f"""
        QFrame {{
            background: rgba(124,92,252,0.055);
            border: 1px solid rgba(124,92,252,0.14);
            border-radius: 14px;
        }}
        QFrame QLabel {{ background: transparent; border: none; }}
    """)
    hl = QVBoxLayout(how)
    hl.setContentsMargins(22, 16, 22, 16)
    hl.setSpacing(6)
    ht = QLabel("How to Use")
    ht.setStyleSheet(f"font-size: 12px; font-weight: 700; color: {T.ACC3}; letter-spacing: 0.1px;")
    hb = QLabel(
        "1.  Select a category from the sidebar.\n"
        "2.  Enable tweaks using the toggle switches.\n"
        "3.  Press  Run Selected Tweaks  — applied silently, no CMD popups.\n"
        "4.  A progress dialog shows real-time status for every tweak.\n"
        "5.  Tweaks marked RISK affect security — create a restore point first."
    )
    hb.setStyleSheet(f"font-size: 11.5px; color: {T.TEXT2}; line-height: 1.8;")
    hl.addWidget(ht)
    hl.addWidget(hb)
    ly.addWidget(how)
    ly.addStretch()

    outer.setWidget(content)
    container = QWidget()
    container.setStyleSheet("background: transparent;")
    cl = QVBoxLayout(container)
    cl.setContentsMargins(0, 0, 0, 0)
    cl.setSpacing(0)
    cl.addWidget(outer)
    container._page_ref = page
    return container


