#  MAIN WINDOW  v3.0
# ══════════════════════════════════════════════════════════
class MainWindow(QMainWindow):
    def __init__(self):
        super().__init__()
        self.setWindowTitle("Astranyx Optimizer")
        try:
            self.setWindowIcon(get_logo_icon())
        except Exception:
            pass
        self.setMinimumSize(1100, 720)
        self.resize(1300, 840)
        self._all_cards = {}
        self._tweaks_db = _tweaks()
        self._build_ui()
        self._activate(0)

    def _build_ui(self):
        central = QWidget()
        self.setCentralWidget(central)
        root = QHBoxLayout(central)
        root.setContentsMargins(0, 0, 0, 0)
        root.setSpacing(0)
        self._build_sidebar(root)
        self._build_content(root)

    def _build_sidebar(self, root):
        sb = QFrame()
        sb.setFixedWidth(224)
        sb.setStyleSheet(
            "background: rgba(9,9,20,0.99);"
            "border-right: 1px solid rgba(255,255,255,0.052);"
        )
        ly = QVBoxLayout(sb)
        ly.setContentsMargins(0, 0, 0, 0)
        ly.setSpacing(0)

        # Logo header
        lw = QFrame()
        lw.setFixedHeight(70)
        lw.setStyleSheet("border-bottom: 1px solid rgba(255,255,255,0.052); background: transparent;")
        ll = QHBoxLayout(lw)
        ll.setContentsMargins(14, 12, 14, 12)
        ll.setSpacing(11)
        li = QLabel()
        li.setFixedSize(44, 44)
        li.setAlignment(Qt.AlignmentFlag.AlignCenter)
        try:
            li.setPixmap(get_logo_pixmap(44))
        except Exception:
            li.setText("A")
            li.setStyleSheet(f"font-size: 22px; font-weight: 900; color: {T.ACC3};")
        ll.addWidget(li)
        txt = QVBoxLayout()
        txt.setSpacing(2)
        ln = QLabel("ASTRANYX")
        ln.setStyleSheet(f"font-size: 13.5px; font-weight: 800; color: {T.ACC3}; letter-spacing: 1.5px;")
        ls = QLabel("OPTIMIZER  v3.0")
        ls.setStyleSheet(f"font-size: 8.5px; color: {T.TEXT3}; letter-spacing: 1.2px; font-weight: 600;")
        txt.addWidget(ln)
        txt.addWidget(ls)
        ll.addLayout(txt)
        ll.addStretch()
        ly.addWidget(lw)

        # Nav
        nav_scroll = QScrollArea()
        nav_scroll.setWidgetResizable(True)
        nav_scroll.setFrameShape(QFrame.Shape.NoFrame)
        nav_scroll.setStyleSheet("background: transparent;")
        nav_scroll.setHorizontalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAlwaysOff)
        nav_scroll.setVerticalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAlwaysOff)
        nw = QWidget()
        nw.setStyleSheet("background: transparent;")
        nl = QVBoxLayout(nw)
        nl.setContentsMargins(0, 12, 0, 0)
        nl.setSpacing(1)

        self._nav_items = []
        labels = ["Dashboard","Quick Fixes","Performance","Network",
                  "Gaming","NVIDIA","Power Plans","Services","Cleaner","Privacy"]

        def nav_sep(text):
            w = QWidget()
            wl = QHBoxLayout(w)
            wl.setContentsMargins(19, 16, 12, 6)
            wl.setSpacing(8)
            lb = QLabel(text)
            lb.setStyleSheet(
                f"font-size: 8.5px; font-weight: 700; color: {T.TEXT3}; letter-spacing: 2px;"
            )
            ln = QFrame()
            ln.setFixedHeight(1)
            ln.setStyleSheet(f"background: {T.BORDER};")
            wl.addWidget(lb)
            wl.addWidget(ln, 1)
            return w

        nl.addWidget(nav_sep("MAIN"))
        ni = NavItem(0, labels[0])
        ni.clicked.connect(self._activate)
        nl.addWidget(ni)
        self._nav_items.append((0, ni))

        nl.addWidget(nav_sep("TWEAKS"))
        for idx in range(1, 10):
            ni = NavItem(idx, labels[idx])
            ni.clicked.connect(self._activate)
            nl.addWidget(ni)
            self._nav_items.append((idx, ni))

        nl.addStretch()
        nav_scroll.setWidget(nw)
        ly.addWidget(nav_scroll)

        # Bottom buttons
        bot = QFrame()
        bot.setStyleSheet("QFrame { border-top: 1px solid rgba(255,255,255,0.052); background: transparent; }")
        bl = QVBoxLayout(bot)
        bl.setContentsMargins(14, 16, 14, 20)
        bl.setSpacing(8)

        self.run_btn = ActionButton("Run Selected Tweaks", "primary")
        self.run_btn.clicked.connect(self._run_tweaks)
        bl.addWidget(self.run_btn)

        self.sel_all_btn = ActionButton("Select All Visible", "secondary")
        self.sel_all_btn.clicked.connect(self._select_all_current)
        bl.addWidget(self.sel_all_btn)

        self.clear_btn = ActionButton("Clear All", "secondary")
        self.clear_btn.clicked.connect(self._clear_all)
        bl.addWidget(self.clear_btn)

        ly.addWidget(bot)
        root.addWidget(sb)

    def _build_content(self, root):
        area = QWidget()
        area.setStyleSheet(f"background: {T.BG};")
        ly = QVBoxLayout(area)
        ly.setContentsMargins(0, 0, 0, 0)
        ly.setSpacing(0)

        # Topbar
        topbar = QFrame()
        topbar.setFixedHeight(52)
        topbar.setStyleSheet(
            "background: rgba(11,11,22,0.97);"
            "border-bottom: 1px solid rgba(255,255,255,0.052);"
        )
        tbl = QHBoxLayout(topbar)
        tbl.setContentsMargins(32, 0, 32, 0)
        tbl.setSpacing(0)
        self._topbar_title = QLabel("Dashboard")
        self._topbar_title.setStyleSheet(
            f"font-size: 13px; font-weight: 700; color: {T.TEXT}; letter-spacing: 0.1px;"
        )
        sep = QLabel("  /  ")
        sep.setStyleSheet(f"font-size: 12px; color: {T.TEXT3};")
        self._topbar_sub = QLabel("Astranyx Optimizer")
        self._topbar_sub.setStyleSheet(f"font-size: 11px; color: {T.TEXT3};")
        tbl.addWidget(self._topbar_title)
        tbl.addWidget(sep)
        tbl.addWidget(self._topbar_sub)
        tbl.addStretch()
        self._selected_lbl = QLabel("0 tweaks selected")
        self._selected_lbl.setStyleSheet(f"font-size: 11px; color: {T.TEXT3};")
        tbl.addWidget(self._selected_lbl)
        ly.addWidget(topbar)

        self.stack = QStackedWidget()
        self.stack.setStyleSheet("background: transparent;")
        ly.addWidget(self.stack)
        self._build_pages()
        root.addWidget(area)

        self._overlay = QWidget(area)
        self._overlay.setStyleSheet("background: rgba(8,8,18,0.82);")
        self._overlay.hide()
        self._progress_dlg = ProgressDialog("Applying Tweaks", area)
        self._progress_dlg.hide()

    def _build_pages(self):
        db = self._tweaks_db
        pages_info = []

        dash = build_dashboard(self)
        self.stack.addWidget(dash)
        pages_info.append((dash, [], "Dashboard", "Astranyx Optimizer v3.0"))

        qf, qf_c = build_multi_section_page([("One-Click Fixes", db["quick"])])
        self.stack.addWidget(scroll_wrap(qf))
        pages_info.append((qf, qf_c, "Quick Fixes", "One-click repairs for common Windows issues"))

        p_pg, p_c = build_tabbed_page([
            ("CPU & Processor", [("CPU Optimizations",  db["perf_cpu"])]),
            ("RAM & Memory",    [("Memory Management",   db["perf_ram"])]),
            ("GPU & Display",   [("Graphics Settings",   db["perf_gpu"])]),
            ("Storage & I/O",   [("Disk & I/O Tweaks",   db["perf_storage"])]),
        ])
        self.stack.addWidget(p_pg)
        pages_info.append((p_pg, [], "Performance", "CPU, RAM, GPU and storage optimizations"))
        self._all_cards[2] = p_c

        n_pg, n_c = build_tabbed_page([
            ("Latency & TCP", [("TCP/IP Optimizations", db["network_latency"])]),
            ("DNS Settings",  [("DNS Configuration",    db["network_dns"])]),
            ("Wi-Fi",         [("Wireless Adapter",     db["network_wifi"])]),
        ])
        self.stack.addWidget(n_pg)
        pages_info.append((n_pg, [], "Network", "Latency, TCP/IP, DNS and Wi-Fi tweaks"))
        self._all_cards[3] = n_c

        g_pg, g_c = build_tabbed_page([
            ("System & GPU",  [("Gaming System Tweaks", db["gaming_system"])]),
            ("Input & Mouse", [("Input Optimization",   db["gaming_input"])]),
        ])
        self.stack.addWidget(g_pg)
        pages_info.append((g_pg, [], "Gaming", "FPS, input latency and game-specific settings"))
        self._all_cards[4] = g_c

        nv_pg, nv_c = build_tabbed_page([
            ("Laptop (Optimus)", [("NVIDIA Laptop Settings",  db["nvidia_laptop"])]),
            ("Desktop",          [("NVIDIA Desktop Settings", db["nvidia_desktop"])]),
        ])
        self.stack.addWidget(nv_pg)
        pages_info.append((nv_pg, [], "NVIDIA", "GPU driver and control panel optimizations"))
        self._all_cards[5] = nv_c

        pw_pg, pw_c = build_tabbed_page([
            ("Laptop Power",  [("Laptop Power Plans & Settings",  db["power_laptop"])]),
            ("Desktop Power", [("Desktop Power Plans & Settings", db["power_desktop"])]),
        ])
        self.stack.addWidget(pw_pg)
        pages_info.append((pw_pg, [], "Power Plans", "Power schemes for laptop and desktop"))
        self._all_cards[6] = pw_c

        sv, sv_c = build_multi_section_page([("Unnecessary Windows Services", db["services"])])
        self.stack.addWidget(scroll_wrap(sv))
        pages_info.append((sv, sv_c, "Services", "Disable unused background Windows services"))

        cl, cl_c = build_multi_section_page([("System Cleanup", db["cleaner"])])
        self.stack.addWidget(scroll_wrap(cl))
        pages_info.append((cl, cl_c, "Cleaner", "Remove junk files, cache and logs"))

        pr_pg, pr_c = build_tabbed_page([
            ("Telemetry", [("Telemetry & Reporting", db["privacy_telemetry"])]),
            ("Tracking",  [("Tracking & Access",     db["privacy_tracking"])]),
            ("Debloat",   [("Bloatware & Ads",       db["privacy_debloat"])]),
        ])
        self.stack.addWidget(pr_pg)
        pages_info.append((pr_pg, [], "Privacy", "Telemetry, tracking, debloat and data protection"))
        self._all_cards[9] = pr_c

        self._pages_info = pages_info
        for idx, cards in {1: qf_c, 7: sv_c, 8: cl_c}.items():
            self._all_cards[idx] = cards

    def _activate(self, idx):
        self.stack.setCurrentIndex(idx)
        for i, ni in self._nav_items:
            ni.setActive(i == idx)
        if idx < len(self._pages_info):
            self._topbar_title.setText(self._pages_info[idx][2])
            self._topbar_sub.setText(self._pages_info[idx][3])
        self._update_counter()

    def _get_current_cards(self):
        idx = self.stack.currentIndex()
        v = self._all_cards.get(idx, [])
        if isinstance(v, dict):
            out = []
            for c in v.values():
                out.extend(c)
            return out
        return v

    def _get_all_cards(self):
        out = []
        for v in self._all_cards.values():
            if isinstance(v, dict):
                for c in v.values():
                    out.extend(c)
            else:
                out.extend(v)
        return out

    def _update_counter(self):
        n = sum(1 for c in self._get_all_cards() if c.is_on())
        self._selected_lbl.setText(f"{n} tweak{'s' if n != 1 else ''} selected")

    def _select_all_current(self):
        for c in self._get_current_cards():
            c.toggle.setChecked(True)
        self._update_counter()

    def _clear_all(self):
        for c in self._get_all_cards():
            c.toggle.setChecked(False)
        self._update_counter()

    def _build_run_list(self):
        selected = []
        tweak_by_id = {}
        for cat_tweaks in self._tweaks_db.values():
            for tw in cat_tweaks:
                tweak_by_id[tw["id"]] = tw
        for c in self._get_all_cards():
            if c.is_on():
                tw = tweak_by_id.get(c.tweak["id"])
                if tw:
                    selected.append(tw)
        return selected

    def _run_tweaks(self):
        tweaks = self._build_run_list()
        if not tweaks:
            orig = self.run_btn.text()
            self.run_btn.setText("No tweaks selected")
            self.run_btn.setEnabled(False)
            QTimer.singleShot(2000, lambda: (
                self.run_btn.setText(orig), self.run_btn.setEnabled(True)
            ))
            return

        self._show_overlay()
        self._progress_dlg.title_lbl.setText(f"Applying {len(tweaks)} Tweaks...")
        self._progress_dlg.title_lbl.setStyleSheet(
            f"font-size: 16px; font-weight: 700; color: {T.TEXT}; letter-spacing: -0.2px;"
        )
        self._progress_dlg.result_lbl.setText("")
        self._progress_dlg.bar.setValue(0)
        self._progress_dlg.pct_lbl.setText("0%")
        self._center_dialog()
        self._progress_dlg.show()
        self._progress_dlg.raise_()

        self.run_btn.setEnabled(False)
        self._worker = TweakWorker(tweaks)
        self._worker.progress.connect(self._on_progress)
        self._worker.done.connect(self._on_done)
        self._worker.start()

    def _on_progress(self, pct, msg):
        self._progress_dlg.update(pct, msg)

    def _on_done(self, ok, fail):
        self._progress_dlg.set_done(
            "Complete",
            f"{ok} succeeded  ·  {fail} failed",
            T.TEAL if fail == 0 else T.GOLD
        )
        self.run_btn.setEnabled(True)
        QTimer.singleShot(3800, self._hide_overlay)
        self._update_counter()

    def _show_overlay(self):
        cw = self.centralWidget()
        self._overlay.setGeometry(0, 0, cw.width(), cw.height())
        self._overlay.raise_()
        self._overlay.show()

    def _hide_overlay(self):
        self._overlay.hide()
        self._progress_dlg.hide()

    def _center_dialog(self):
        cw = self.centralWidget()
        if cw:
            x = (cw.width()  - self._progress_dlg.width())  // 2
            y = (cw.height() - self._progress_dlg.height()) // 2
            self._progress_dlg.move(x, max(y, 60))
            self._progress_dlg.setParent(cw)
            self._progress_dlg.raise_()

    def resizeEvent(self, e):
        super().resizeEvent(e)
        cw = self.centralWidget()
        if cw:
            self._overlay.setGeometry(0, 0, cw.width(), cw.height())
            if self._progress_dlg.isVisible():
                self._center_dialog()


# ══════════════════════════════════════════════════════════
#  ENTRY POINT
# ══════════════════════════════════════════════════════════
def main():
    if not is_admin():
        relaunch_as_admin()
        return

    app = QApplication(sys.argv)
    app.setStyle("Fusion")

    pal = QPalette()
    pal.setColor(QPalette.ColorRole.Window,          QColor(T.BG))
    pal.setColor(QPalette.ColorRole.WindowText,      QColor(T.TEXT))
    pal.setColor(QPalette.ColorRole.Base,            QColor(T.BG2))
    pal.setColor(QPalette.ColorRole.AlternateBase,   QColor(T.BG3))
    pal.setColor(QPalette.ColorRole.Text,            QColor(T.TEXT))
    pal.setColor(QPalette.ColorRole.Button,          QColor(T.PANEL))
    pal.setColor(QPalette.ColorRole.ButtonText,      QColor(T.TEXT))
    pal.setColor(QPalette.ColorRole.Highlight,       QColor(T.ACC))
    pal.setColor(QPalette.ColorRole.HighlightedText, QColor("#ffffff"))
    app.setPalette(pal)
    app.setStyleSheet(APP_SS)

    try:
        app.setWindowIcon(get_logo_icon())
    except Exception:
        pass

    w = MainWindow()
    w.show()
    sys.exit(app.exec())


if __name__ == "__main__":
    main()
